import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, useNavigate, useParams } from 'react-router-dom';
import Navbar from './components/Navbar/Navbar';
import Footer from './components/Footer/Footer';
import Hero from './features/landing/Hero';
import HowItWorks from './features/landing/HowItWorks';
import JobServices from './features/landing/JobServices';
import Testimonials from './features/landing/Testimonials';
import CTA from './features/landing/CTA';
import JobListContainer from './features/eksplorasi/JobListContainer';
import Login from './components/auth/Login';
import Register from './components/auth/Register';
import JobDetail from './components/jobs/JobDetail';
import JobPublisher from './features/hrd/JobPublisher';
import CompanyBrandingForm from './features/dashboard/CompanyBrandingForm';

const JobDetailWrapper = () => {
    const { id } = useParams();
    return <JobDetail job={{ id, title: 'Lowongan Detail', company: 'PasukanYerusSolo' }} />;
};

const ViewAllButton = () => {
    const navigate = useNavigate();
    return (
        <div style={{ textAlign: 'center', marginTop: '20px' }}>
            <button 
                onClick={() => navigate('/eksplorasi')} 
                style={{ padding: '10px 24px', background: 'transparent', border: '1px solid #ea580c', color: '#ea580c', borderRadius: '8px', cursor: 'pointer' }}
            >
                Lihat Semua Lowongan
            </button>
        </div>
    );
};

const App = () => {
    const [isAuthenticated, setIsAuthenticated] = useState(!!localStorage.getItem('token'));
    const [userRole, setUserRole] = useState(localStorage.getItem('role'));

    const handleLogout = () => {
        localStorage.removeItem('token');
        localStorage.removeItem('role');
        setIsAuthenticated(false);
        setUserRole(null);
        window.location.href = '/';
    };

    return (
        <div style={{ backgroundColor: '#0c0a09', minHeight: '100vh', color: '#fff' }}>
            <Navbar 
                isAuthenticated={isAuthenticated} 
                userRole={userRole} 
                handleLogout={handleLogout} 
            />
            <main>
                <Routes>
                    <Route path="/" element={
                        <>
                            <Hero />
                            <HowItWorks />
                            <JobServices />
                            <section className="job-listings-section" style={{ maxWidth: '1200px', margin: '80px auto', padding: '0 20px' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '40px', flexWrap: 'wrap', gap: '20px' }}>
                                    <div>
                                        <span style={{ color: '#ea580c', fontSize: '14px', fontWeight: 'bold', letterSpacing: '2px', textTransform: 'uppercase', marginBottom: '8px', display: 'block' }}>Lowongan Terbaru</span>
                                        <h2 style={{ fontSize: '32px', fontWeight: 'bold', color: '#fef3c7', margin: 0 }}>Temukan Karir Impianmu</h2>
                                    </div>
                                    <button 
                                        onClick={() => navigate('/eksplorasi')} 
                                        style={{ padding: '12px 24px', background: 'transparent', border: '1px solid #ea580c', color: '#ea580c', borderRadius: '8px', cursor: 'pointer', fontWeight: '600', transition: 'all 0.3s ease' }}
                                        onMouseEnter={(e) => { e.currentTarget.style.backgroundColor = '#ea580c'; e.currentTarget.style.color = '#fff'; }}
                                        onMouseLeave={(e) => { e.currentTarget.style.backgroundColor = 'transparent'; e.currentTarget.style.color = '#ea580c'; }}
                                    >
                                        Lihat Semua Lowongan →
                                    </button>
                                </div>
                                <JobListContainer variant="simple" limit={4} />
                            </section>
                            <Testimonials />
                            <CTA />
                        </>
                    } />
                    <Route path="/eksplorasi" element={
                        <div style={{ maxWidth: '1200px', margin: '40px auto', padding: '0 20px' }}>
                            <div style={{ marginBottom: '30px' }}>
                                <h1 style={{ fontSize: '36px', marginBottom: '10px', color: '#fef3c7' }}>Semua Lowongan Kerja</h1>
                                <p style={{ color: '#a8a29e' }}>Temukan berbagai peluang karir menarik dari perusahaan-perusahaan terbaik</p>
                            </div>
                            <JobListContainer variant="full" />
                        </div>
                    } />
                    <Route path="/job/:id" element={<JobDetailWrapper />} />
                    <Route path="/login" element={<Login onLoginSuccess={() => {setIsAuthenticated(true);setUserRole(localStorage.getItem('role'));}} />}/>
                    <Route path="/register" element={<Register />} />
                    <Route path="/hrd/dashboard" element={<JobPublisher />} />
                    <Route path="/hrd/branding" element={<CompanyBrandingForm />} />
                </Routes>
            </main>
            <Footer />
        </div>
    );
};

const AppWrapper = () => {
    const navigate = useNavigate();
    return <App navigate={navigate} />;
};

const AppWithRouter = () => (
    <Router>
        <App />
    </Router>
);

export default AppWithRouter;
